--

LOCK TABLES `itm_main_htmlblock` WRITE;
/*!40000 ALTER TABLE `itm_main_htmlblock` DISABLE KEYS */;
INSERT INTO `itm_main_htmlblock` VALUES (1,'index-about-txt','<h2 class=\"title\">О НАШЕМ КЛУБЕ</h2>\r\n\r\n<p>&laquo;Новая&nbsp;Эволюция&raquo; &ndash; это первый современный фитнес-клуб нового формата, соответствующий требованиям и ожиданиям жителей самого динамично развивающегося района г. Рязани.</p>\r\n\r\n<p>Наш клуб сочетает в себе максимально удобное расположение, комфортные условия для занятий, предлагает полный спектр фитнес-услуг на высоком уровне и предоставляет уникальную возможность погрузиться в атмосферу здорового образа жизни каждому человеку.</p>\r\n\r\n<p>Философия нашего бренда заключается в том, что человек сам создает свою жизнь, а наш клуб и регулярные занятия в нем помогают сделать ее наполненной радостью, красотой, здоровьем и благополучием. Поэтому наш девиз звучит так: &laquo;Создай свое будущее&raquo;.</p>'),(2,'index-benefits-text','\n	    <h2 class=\"title\">НАШИ ПРЕИМУЩЕСТВА</h2>\n        '),(3,'index-news-text','\n	    <h2 class=\"title\">Что нового</h2>\n        '),(4,'index-stock-text','\n	        <h2 class=\"title\">акции</h2>\n             '),(5,'header-phone','\n		    <a href=\"tel: 84912559594\" class=\"header-phone\"><span class=\"phone-img\"><img src=\"/static/global/img/phone.svg\" alt=\"ico\"></span><span class=\"phone-txt\">+7 (4912) 55-95-94</span></a>\n			'),(6,'footer-content','<ul class=\"footer-link\">\r\n	<li><span class=\"ico-img\"><img alt=\"ico\" src=\"/static/global/img/home.svg\" /></span><span class=\"ico-txt\">г. Рязань, р-он Дашково-Песочня, ул. Новосёлов, д. 53Д</span></li>\r\n	<li><a class=\"footer-phone\" href=\"tel: 84912559594\"><span class=\"ico-img\"><img alt=\"ico\" src=\"/static/global/img/phone.svg\" /></span><span class=\"ico-txt\">+7 (4912) 55-95-94</span></a></li>\r\n</ul>'),(7,'development','<p class=\"develope\">РАЗРАБОТКА И ПОДДЕРЖКА ПРОЕКТА - <a href=\"https://itmedia.site/\" target=\"_blank\">студия IT-media</a></p>'),(8,'team-txt','\n            <h2 class=\"title\">ХОЧЕШЬ СТАТЬ ТРЕНЕРОМ ИЛИ ИНСТРУКТОРОМ В НАШЕЙ КОМАНДЕ?</h2>  \n            <p>Если ты хочешь развиваться сам, делать мир и людей вокруг себя лучше, если ты веришь, что ты и каждый человек должен быть здоровым и красивым, если ты хочешь работать в уникальном и перспективном клубе города, присылай свое резюме, мы будем рады, если ты присоединишься к нашей команде успешных и энергичных людей.</p>\n            '),(9,'contacts-address-txt','<p>г. Рязань, р-он Дашково-Песочня, ул. Новосёлов, д. 53Д</p>'),(10,'contacts-phone-txt','\n				<a href=\"tel: 84912559594\">+7 (4912) 55-95-94</a>\n                '),(11,'contacts-email-txt','\n				<a href=\"mailto: sales@evolution-fitness.ru\">sales@evolution-fitness.ru</a>\n                '),(12,'contacts-worktime-txt','<ul>\r\n	<li>Пн-пт: с 06:00 до 00:00</li>\r\n	<li>Сб-вс: с 08:00 до 22:00</li>\r\n</ul>'),(13,'contacts-worktime-w-txt','<p>Для допуска&nbsp;у вас должны быть с собой:<br />\r\n- QR-код или оригинал справки о наличии полной вакцинации;<br />\r\n- оригинал справки о медотводе;<br />\r\n- QR-код или оригинал справки о том, что переболели менее 6 месяцев назад ковидом;<br />\r\nОБЯЗАТЕЛЬНО оригинал документа, &nbsp;подтверждающего личность клиента.</p>');
/*!40000 ALTER TABLE `itm_main_htmlblock` ENABLE KEYS */;
UNLOCK TABLES;

