INSERT INTO `news_news` VALUES (5,1,'2021-08-19 12:47:53.000000',5,'Открытие фитнес клуба на Новосёлов 53Д','<p>Друзья! Наступило время обновлений! Мы меняемся, а вы с нами?&nbsp;<br />\r\n⠀<br />\r\nСовсем скоро мы открываем обновлённый фитнес, всего в 2 минутах ходьбы от нынешнего местоположения&nbsp;по адресу - ул. Новоселов 53д.<br />\r\n⠀<br />\r\nДочитай до конца, там такое...<br />\r\n⠀<br />\r\nНа протяжении 2-х лет работы мы собирали все отзывы и пожелания, и теперь воплощаем их в жизнь.<br />\r\n⠀<br />\r\nНовый клуб это:<br />\r\n- 3 этажа фитнеса;<br />\r\n⁃ Собственная парковка для наших клиентов;<br />\r\n- 20 м от остановки общественного транспорта;<br />\r\n- Детская игровая комната на 1-ом этаже нашего здания, где вы за сможете оставлять своих детишек на время тренировок под присмотром опытного воспитателя!<br />\r\n⠀<br />\r\nНа 2-ом этаже вас ждет просторная кардио зона с множеством беговых дорожек, велосипедов и эллипсоидов. Помимо этого вы сможете проводить высокоинтенсивные тренировки в полноценной кросс фит зоне, а также вас порадует долгожданная зона единоборств и ринг.<br />\r\nВы сможете расслабиться в удобных массажных креслах фирмы Yamaguchi от наших партнеров (у каждого резидента будет один бесплатный сеанс в день) или же выпить чашечку кофе или протеиновый коктейль в уютном фитнес баре!<br />\r\n⠀<br />\r\nНа 3-ем этаже вас ждёт множество силовых тренажеров, где каждый сможет подобрать для себя то оборудование, которое необходимо для достижения желаемого результата!<br />\r\n⠀<br />\r\nНа 4-ом этаже расположены 2 просторных зала групповых программ с панорамными окнами. Больше не нужно записываться, места хватит всем. К уже полюбившимся направлениям добавятся новые, такие как аэройога, банджи и др.!<br />\r\nДля любителей настольного тенниса, мы предлагаем профессиональные столы и оборудование, чтобы ваша игра доставила вам максимум удовольствия.<br />\r\n⠀<br />\r\nБольшие раздевалки с просторными душевыми, раздельными финскими саунами и обливными ведрами сделают завершение тренировки истинным наслаждением!<br />\r\nНу и конечно, больше не нужно носить полотенце с собой, его можно будет брать у наших администраторов.<br />\r\nИстинных ценителей массажа ждут профессиональные массажисты.</p>','news_img/1_hmX2JYO.jpg','news_img/1_w7RaEpq.jpg','otkrytie-fitnes-kluba-na-novosyolov-53-d','<p>Друзья! Наступило время обновлений! Мы меняемся, а вы с нами?&nbsp;</p>'),(6,1,'2021-08-19 13:44:56.000000',6,'ГОНКА ГЕРОЕВ 2021','<p>17 июля состоялось великое событие в сфере фитнеса и аутдор тренировок #гонкагероев2021&nbsp;!</p>\r\n\r\n<p>Фитнес клуб @evolution_rzn совместно с @dencerr13 собрали и подготовили команду сильных духом.</p>\r\n\r\n<p>Мы все справились с этим!</p>\r\n\r\n<p>Преодолели себя и свои страхи: забраться на высоту, спрыгнуть всей командой в глубокое озеро, вытаскивать друг друга и помогать в следующем препятствии&hellip;</p>\r\n\r\n<p>Бежать пришлось более 8 км и преодолеть 36 препятствий на пути. Грязь, солнце, рукоходы&nbsp;и многое другое ждало нас на этой гонке.</p>\r\n\r\n<p>Взвод &laquo;1267&raquo;<br />\r\n96 место из 200 взводов.</p>\r\n\r\n<p>Настоящая командная работа!</p>\r\n\r\n<p>Молодцы!</p>','news_img/1_cJoWEiN.jpg','news_img/1_eJfa9aQ.jpg','gonka-geroev-2021','<p>17 июля состоялось великое событие в сфере фитнеса и аутдор тренировок #гонкагероев2021&nbsp;!</p>'),(7,1,'2021-08-27 16:18:43.000000',7,'1 сентября года открывает свои двери Школа фитнеса «Эволюция»','<p>Это первый фитнес-клуб в Рязани, где дети и подростки с увлечением смогут заниматься спортом и фитнесом под руководством профессиональных тренеров.<br />\r\nДаже самые маленькие спортсмены будут чувствовать себя комфортно и безопасно.</p>\r\n\r\n<p>В школе фитнеса &laquo;Эволюция&raquo; большой выбор направлений занятий:</p>\r\n\r\n<ul>\r\n	<li>бокс;</li>\r\n	<li>карате;</li>\r\n	<li>рукопашный бой;</li>\r\n	<li>Zumba kids;</li>\r\n	<li>современная и детская хореография;</li>\r\n	<li>гимнастика;</li>\r\n	<li>детская йога;</li>\r\n	<li>тренажёрный зал;</li>\r\n	<li>кардиозона.</li>\r\n</ul>\r\n\r\n<p>Профессиональные тренеры&nbsp;школы фитнеса &laquo;Эволюция&raquo; проходят обязательное обучение по специально разработанным стандартам, а также ежегодную аттестацию.</p>\r\n\r\n<p>По вопросам записи на групповые занятия и приобретения абонемента пиши в Директ или звони.</p>\r\n\r\n<p>Дашково-Песочня, Новосёлов 53Д и Васильевская 7.<br />\r\n<a href=\"tel: 84912559594\" style=\"color:#ffffff;\">+7 (4912) 55-95-94.</a></p>','news_img/1_FYu1y0x.jpg','news_img/1_SrNB1cG.jpg','1-sentyabrya-goda-otkryvaet-svoi-dveri-shkola-fitn','<p>Это первый фитнес-клуб в Рязани, где дети и подростки с увлечением смогут заниматься спортом и фитнесом под руководством профессиональных тренеров.</p>'),(8,0,'2021-10-26 21:34:41.000000',8,'УВАЖАЕМЫЕ КЛИЕНТЫ И ГОСТИ НАШЕГО ФИТНЕС КЛУБА!','<p>Пунктом 5. распоряжения Губернатора Рязанской области № 309 &ndash;рг от 22.10.2021 года &laquo;О внесении изменений в распоряжение Губернатора Рязанской области от 17.03.2020 года № 70-рг, Распоряжение дополнено п. 12.1 следующего содержания:<br />\r\n&laquo;Установить, что с 30 октября 2021 года по 07 ноября 2021 года посещение гражданами, достигшими возраста 18 лет, фитнес-центров, плавательных бассейнов, допускается с предъявлением документа, удостоверяющего личность при наличии у таких граждан:<br />\r\n1. Либо QR-кода, полученного с использованием специализированного приложения Единого портала государственных и муниципальных услуг, которым подтверждается получение гражданами второго компонента вакцины от новой коронавирусной инфекции (COVID‑19), прошедшей государственную регистрацию в Российской Федерации (далее &ndash; вакцина), или однокомпонентной вакцины;<br />\r\n2. Либо QR-кода, полученного с использованием специализированного приложения Единого портала государственных и муниципальных услуг, которым подтверждается то, что они перенесли новую коронавирусную инфекцию (COVID‑19) и с даты их выздоровления прошло не более 6 календарных месяцев;<br />\r\n3. Либо справки медицинской организации, подтверждающей получение гражданами второго компонента вакцины или однокомпонентной вакцины;<br />\r\n4. Либо справки медицинской организации, подтверждающей, что они перенесли новую коронавирусную инфекцию (COVID‑19) и с даты их выздоровления прошло не более 6 календарных месяцев;<br />\r\n5. Либо справки медицинской организации, подтверждающей наличие медицинского отвода от вакцинации против новой коронавирусной инфекции (COVID‑19), выданной медицинской организацией, где наблюдается пациент по заболеванию, являющемуся медицинским отводом.<br />\r\nВ соответствии с п. 42 Распоряжения: &laquo;оказание услуг несовершеннолетним лицам (не достигшим возраста 18 лет) в период с 30.10.2021 года по 07.11.2021 в фитнес-центрах ПРИОСТАНОВЛЕНО&raquo;.</p>\r\n\r\n<p>Просим Вас учесть вышеуказанные требования при посещении фитнес клуба в период с 30.10.2021 года по 07.11.2021 года.</p>','news_img/1_lEX6E2n.jpg','news_img/1_bR8gdP8.jpg','uvazhaemye-klienty-i-gosti-nashego-fitnes-kluba','<p>Пунктом 5. распоряжения Губернатора Рязанской области № 309 &ndash;рг от 22.10.2021 года &laquo;О внесении изменений в распоряжение Губернатора Рязанской области от 17.03.2020 года № 70-рг, Распоряжение дополнено п. 12.1 следующего содержания:</p>'),(9,1,'2021-11-22 17:14:46.000000',9,'Дорогие друзья!','<p>Мы возвращаемся в прежний режим работы:<br />\r\nПн-пт: с 06:00 до 00:00<br />\r\nСб-вс: с 08:00 до 22:00</p>\r\n\r\n<p>Не забываем соблюдать распоряжение губернатора!<br />\r\nДля допуска в фитнес клуб &laquo;Эволюция&raquo; у вас должны быть с собой:<br />\r\n- QR-код или оригинал справки о наличии полной вакцинации;<br />\r\n- оригинал справки о медотводе;<br />\r\n- QR-код или оригинал справки о том, что переболели менее 6 месяцев назад ковидом;<br />\r\nОБЯЗАТЕЛЬНО оригинал документа, &nbsp;подтверждающего личность клиента.</p>\r\n\r\n<p>Ждём всех в нашем фитнес клубе!</p>','news_img/2.jpg','news_img/2_RR03GEF.jpg','dorogie-druzya','<p>Мы возвращаемся в прежний режим работы:<br />\r\nПн-пт: с 06:00 до 00:00<br />\r\nСб-вс: с 08:00 до 22:00</p>'),(10,1,'2021-12-06 17:41:23.000000',10,'Мы приняли участие в «Городской зарядке»','<p>Координатор тренажёрного зала Артём Бизюков провел небольшое соревнование среди желающих.<br />\r\nДевушки и парни оказались достойными соперниками!<br />\r\nБез подарка не ушёл никто! Всем участникам вручили абонементы в фитнес клуб Эволюция.</p>\r\n\r\n<p>Александр Гордюшин, тренер по боксу и джиу-джитсу, и<br />\r\nЕгор Фетисов, помощник тренера по боксу и джиу-джитсу, выступили с показательными выступлениями по боксу от Школы фитнеса Эволюция и пригласили всех желающих на бесплатные пробные тренировки.</p>\r\n\r\n<p>Спасибо большое организаторам за такое замечательное мероприятие!</p>\r\n\r\n<p>Ждём всех!</p>\r\n\r\n<p>Первое пробное занятие совершенно БЕСПЛАТНО</p>\r\n\r\n<p>По всем интересующим Вас вопросам с удовольствием проконсультируем в Директ<br />\r\nили по телефону:</p>\r\n\r\n<p>Дашково-Песочня, ул. Васильевская 7.<br />\r\n+7 (4912) 55-95-94</p>','news_img/1_aULV5ad.jpg','news_img/1_3u9Qq6g.jpg','4-dekabrya-fitnes-klub-evolyuciya-i-shkola-fitnesa','<p>4 декабря Фитнес клуб &laquo;Эволюция&raquo; и Школа фитнеса &laquo;Эволюция&raquo; приняли участие в &laquo;Городской зарядке&raquo;</p>'),(11,1,'2021-12-06 17:45:58.000000',11,'Дорогие друзья, мы с приятными новостями!','<p>Министерство спорта Российской Федерации утвердило перечень физкультурно-спортивных организаций и индивидуальных предпринимателей, осуществляющих физкультурно-оздоровительные услуги, за которые россияне смогут получить социальный налоговый вычет.</p>\r\n\r\n<p>Наш фитнес клуб &laquo;Эволюция&raquo; вошёл в этот перечень.</p>\r\n\r\n<p>Теперь покупая абонемент в наш фитнес клуб в 2022 году, вы можете получить вычет по НДФЛ.</p>\r\n\r\n<p>Получение налогового вычета на занятия спортом будет мало чем отличаться от любого другого социального налогового вычета. Вам необходимо быть плательщиком НДФЛ и иметь документы, подтверждающие фактические расходы на оплату физкультурно-оздоровительных услуг (копии договоров, кассовые чеки). Обратиться за оформлением вычета можно в районную ИФНС или к работодателю. Получить вычет можно не только за себя, но и за детей.</p>\r\n\r\n<p>Максимальная сумма трат, с которых можно будет получить налоговый вычет, составит 120 тысяч рублей. Гражданин вправе получить вычет в размере 13%, что не должно превышать 15,6 тысячи рублей.</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани? Тогда пиши в Директ или звони ','news_img/IMG_7563.PNG','news_img/IMG_7563_RM4fVEI.PNG','dorogie-druzya-my-s-priyatnymi-novostyami','<p>Теперь покупая абонемент в наш фитнес клуб в 2022 году, вы можете получить вычет по НДФЛ.</p>'),(12,0,'2021-12-22 22:13:40.000000',12,'День открытых дверей Детская Эволюция!','<p>Дорогие друзья!</p>\r\n\r\n<p>Приглашаем ВСЕХ день открытых дверей в Школе фитнеса &laquo;Эволюция&raquo;, который состоится 25 декабря 2021 года в 11:00.</p>\r\n\r\n<p>Расписание мероприятия:</p>\r\n\r\n<p>11:00 КАРАТЭ Илья Гриднев<br />\r\n12:00 ОФП Софи Андреасян<br />\r\n13:00 ВЕСЁЛЫЕ СТАРТЫ<br />\r\nУвлекательное состязание для детей, которое зарядит бодростью и хорошим настроением<br />\r\n14:00 ДЕТСКАЯ ХОРЕОГРАФИЯ Алена Куревлева<br />\r\n15:00 ДЕТСКАЯ ГИМНАСТИКА Алена Куревлева<br />\r\n16:00 ZUMBA KIDS Юлия Горелова<br />\r\n17:00 РУКОПАШНЫЙ БОЙ Михаил Ермаков<br />\r\n18:00 НОВОГОДНИЕ СТАРТЫ с Дед Морозом<br />\r\nКонкурсы, призы, хорошее настроение!</p>\r\n\r\n<p>Также, вы можете познакомиться с нашим тренажёрным залом и позаниматься.</p>\r\n\r\n<p>Ждём всех и взрослых и маленьких!</p>\r\n\r\n<p>Лицам старше 18 лет вход строго по QR-коду.</p>','news_img/IMG_7921.JPG','news_img/IMG_7921_4rQoaT0.JPG','den-otkrytyh-dverej-detskaya-evolyuciya','<p>Приглашаем ВСЕХ день открытых дверей в Школе фитнеса &laquo;Эволюция&raquo;, который состоится 25 декабря 2021 года в 11:00</p>'),(13,1,'2021-12-22 22:14:51.000000',13,'День открытых дверей новая Эволюция','<p>Дорогие друзья!</p>\r\n\r\n<p>Приглашаем ВСЕХ на день открытых дверей в Фитнес клубе &laquo;Эволюция&raquo;, который состоится 25 декабря 2021 года.</p>\r\n\r\n<p>Расписание мастер-классов и семинаров:</p>\r\n\r\n<p>9:00 Алексей Николаев<br />\r\nВыйти из предновогодней депрессии<br />\r\nЙога растяжка и медитация как средство подготовки к состоянию ленивого и сытого кота. (2 часа)</p>\r\n\r\n<p>11:00 Артём Бизюков<br />\r\nДиета 21века.<br />\r\nОсновы рационального питания или как перестать верить в волшебную таблетку. (1 час)</p>\r\n\r\n<p>12:00 Денис Дроздов<br />\r\nМК Табата<br />\r\nВысокоинтенсивная интервальная жиросжигающая тренировка. Хотите быстро похудеть и качественно улучшить свою форму-тренировка.<br />\r\nТабата отличный способ достижения поставленных целей! (1 час)</p>\r\n\r\n<p>13:00 Анастасия Хоменко<br />\r\nСколиоз<br />\r\nКак распознать у ребёнка? Алгоритм дальнейших действий. ( 1 час)</p>\r\n\r\n<p>18:00-20:00 Приглашаем на новогоднюю танцевальную вечеринку, включающую практически все танцевальные направления под зажигательные треки!<br />\r\nВечеринка пройдёт в стиле &laquo;Dance party&raquo; &nbsp;с дискотечными шарами и ночной атмосферой !!<br />\r\nДаже если ты совсем новичок и никогда не занимался танцами, наш танцпол и инструкторы научат раскрепощению, новым движениям и ты не захочешь уходить домой !!</p>\r\n\r\n<p>Приглашаем всех познакомиться с нашим фитнес клубом!</p>\r\n\r\n<p>Посетить тренажёрный зал, финскую сауну, фитнес-бар, записаться на бесплатную персональную тренировку.</p>\r\n\r\n<p>На бесплатную персональную тренировку можете записаться уже сейчас по ниже указанному номеру или написать в Директ.</p>\r\n\r\n<p>Ждём ВАС!<br />\r\nБудет не только весело, но и познавательно!</p>\r\n\r\n<p>Лицам старше 18 лет вход строго по QR-коду.</p>','news_img/IMG_7924.JPG','news_img/IMG_7924_Dr2kvuM.JPG','den-otkrytyh-dverej-novaya-evolyuciya','<p>Приглашаем ВСЕХ на день открытых дверей в Фитнес клубе &laquo;Эволюция&raquo;, который состоится 25 декабря 2021 года.</p>'),(14,1,'2022-05-26 16:13:40.000000',14,'ФИКСИРУЕМ ЦЕНЫ!','<p>Пока цены непредсказуемо меняются и наводят панику, с нами вы под надёжной защитой!</p>\r\n\r\n<p>Фитнес Клуб Эволюция Рязань фиксирует стоимость своих услуг.</p>\r\n\r\n<p>Лучшее вложение, на наш взгляд, - это вложение в себя, своё здоровье, эмоциональное состояние и фигуру.</p>\r\n\r\n<p>*Прайс действителен с 01.06.2022 г.</p>','news_img/WhatsApp_Image_2022-05-26_at_13.15.25.jpeg','news_img/WhatsApp_Image_2022-05-26_at_13.15.25_BLIie24.jpeg','fiksiruem-ceny','<p>Пока цены непредсказуемо меняются и наводят панику, с нами вы под надёжной защитой!</p>'),(15,1,'2022-06-19 10:53:53.000000',15,'23 июня - день рождения Фитнес Клуба Эволюция!','<p>Уже совсем скоро, 23 июня, празднуем день рождения Фитнес Клуба Эволюция!</p>\r\n\r\n<p>Приглашаем всех вас на наш праздник! Обычно в дни рождения принято получать подарки, но в этот день мы сами будем делать сюрпризы своим прекрасным гостям!<br />\r\n&nbsp;<br />\r\nВас ждет невероятный заряд драйва, а так же:<br />\r\n- командные соревнования во главе с нашими любимыми тренерами;<br />\r\n- веселые конкурсы и интересные викторины;&nbsp;<br />\r\n- вечеринка с фуршетом;&nbsp;<br />\r\n- розыгрыш безлимитных абонементов, сроком от месяца до года.<br />\r\n&nbsp;<br />\r\nПрисоединяйтесь!<br />\r\nОтправляйте + в комментарии, если ждёте праздник также сильно, как и мы.<br />\r\n&nbsp;<br />\r\n23 июня с 18:00 до 22:00 (сбор гостей в 18:00).&nbsp;<br />\r\nМесто проведения: Дашково-Песочня, ул. Новоселов, 53Д.<br />\r\n&nbsp;<br />\r\nПодробнее у наших менеджеров по ссылке vk.me/evolution_rzn или звони:</p>\r\n\r\n<h1><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h1>','news_img/ap9p4j8i0o4.jpg','news_img/ap9p4j8i0o4_u6I5RLN.jpg','23-iyunya-den-rozhdeniya-fitnes-kluba-evolyuciya','<p>Приглашаем всех вас на наш праздник!</p>'),(16,1,'2022-06-19 10:57:13.000000',16,'ВНИМАНИЕ КОНКУРС!','<p>День рождения Фитнес Клуба &laquo;Эволюция&raquo;! В честь этого события, которое состоится 23 июня, мы решили разыграть безлимитный абонемент на 12 месяцев.<br />\r\n&nbsp;<br />\r\nПравила конкурса:&nbsp;<br />\r\n- Сделай репост данной записи;&nbsp;<br />\r\n- Будь подписчиком Фитнес Клуб Эволюция Рязань;<br />\r\n- 23 июня мы подведем итоги в прямом эфире на нашем празднике!&nbsp;<br />\r\n&nbsp;<br />\r\nПриятный сюрприз, мы УДВОИМ приз, если победитель в момент розыгрыша будет присутствовать на нашем мероприятии и подарим целых 2 годовых абонемента!&nbsp;<br />\r\n&nbsp;<br />\r\n&bull; 23 июня с 18:00 до 22:00 (сбор гостей в 18:00).&nbsp;<br />\r\n&bull; Место проведения: ул. Новоселов, 53Д.&nbsp;<br />\r\n&nbsp;<br />\r\nПодробнее у наших менеджеров по ссылке vk.me/evolution_rzn или звони:</p>\r\n\r\n<h1><a href=\"tel: +74912559594\"><strong>+7 (4912) 55-95-94</strong></a></h1>','news_img/RfZmkzJ5GL0.jpg','news_img/RfZmkzJ5GL0_WU45Ixc.jpg','vnimanie-konkurs','<p>В честь нашего дня рождения, мы решили разыграть безлимитный абонемент на 12 месяцев.</p>'),(17,1,'2022-10-12 15:54:28.000000',17,'Старт проекта «Total Evolution»!','<p>Постоянная борьба с лишним весом не даёт результатов и вы уже отчаялись обрести хорошую форму? Друзья, именно для вас мы объявляем набор заявок для участия в проекте &laquo;Total Evolution&raquo;.</p>\r\n\r\n<p>Что вас ждет в проекте?<br />\r\n2,5 месяца усердной работы над собой под чутким руководством тренеров фитнес клуба &laquo;Эволюция&raquo; для достижения наилучшего результата.</p>\r\n\r\n<p>Мы будем следить за преображением участников и по завершению определим победителей, которые получат главный приз &mdash; годовой безлимитный абонемент в фитнес клуб &laquo;Эволюция&raquo;!</p>\r\n\r\n<p>Почему именно &laquo;Total Evolution&raquo;?<br />\r\n* Индивидуальная программа тренировок в зале с личным фитнес-тренером.<br />\r\n* Специалист по питанию научит самостоятельно составлять сбалансированный рацион питания для достижения ваших целей.<br />\r\n* Поддержка и мотивация от тренеров, проработка &laquo;барьеров&raquo; с психологом.<br />\r\n* Все участники получат полезные подарки от наших партнеров.</p>\r\n\r\n<p>Вы находитесь в одном шаге чтобы изменить себя и стать лучше, сбросить лишние килограммы, начать правильно питаться, стать стройнее и жить в своё удовольствие!</p>\r\n\r\n<p><strong>СТАРТ &ndash; 15 ОКТЯБРЯ!</strong></p>\r\n\r\n<p>Хотите принять участие? Пишите в комментариях или отправьте личное сообщение <a href=\"https://vk.me/evolution_rzn\" target=\"_blank\">vk.me/evolution_rzn</a> &laquo;Хочу в проект&raquo; и мы с вами свяжемся.</p>','news_img/screen-12-10-22-3_1.jpg','news_img/screen-12-10-22-3_1_DkVJ0gH.jpg','start-proekta-total-evolution','<p>Постоянная борьба с лишним весом не даёт результатов и вы уже отчаялись обрести хорошую форму?</p>'),(18,1,'2022-11-03 18:15:57.000000',18,'Фитнес-проект «Total Evolution» - стартовал!','<p><span style=\"font-size:20px\">Уже на первой встрече мы:</span><br />\r\n<br />\r\n- Провели консультацию по питанию, раздали полезные памятки для закрепления знаний.&nbsp;<br />\r\n- Познакомились с психологом, который будет сопровождать участников на протяжении всего проекта.&nbsp;<br />\r\n- Сделали замеры и фото &laquo;до&raquo; всех участников.&nbsp;</p>\r\n\r\n<p><span style=\"font-size:20px\">Дальше - больше!</span><br />\r\nПодписывайтесь на наши обновления, будем следить за преображением наших участников вместе!</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани?&nbsp;Тогда пиши <a href=\"http://vk.me/evolution_rzn\">vk.me/evolution_rzn</a><br />\r\nили звони <span style=\"font-size:20px\">8 (4912) 55-95-94</span>.</p>','news_img/IMG_4532.PNG','news_img/IMG_4532_qZTm1g5.PNG','fitnes-proekt-total-evolution-startoval','<p>Делимся с вами приятными новостями...</p>'),(19,1,'2022-11-14 16:13:24.000000',19,'Мы все этого очень ждали!','<p>Сайкл&nbsp;&mdash; это групповая тренировка для мужчин и женщин на стационарных велосипедах, которая имитирует гонки различной интенсивности. Программа стала популярной в фитнес-клубах благодаря своей невероятной эффективности. Если вы хотите привести себя в отличную форму в короткие сроки, то аэробная велотренировка &mdash; это то, что вам нужно.</p>\r\n\r\n<p>На первый взгляд может показаться, что подобный тренинг легок. Это далеко не так. Даже для мужчин сайклинг часто оказывается трудновыполнимым занятием. Качественные тренировки помогают похудеть, убрать целлюлит с проблемных зон и укрепить мышцы.</p>\r\n\r\n<p>В отличие от других аэробных тренировок, таких как фитнес, бег, легкая атлетика, а также силовых тренингов, сайклинг не даёт усиленных нагрузок на суставы и позвоночник.</p>\r\n\r\n<p>Возрастных ограничений, как таковых, для проведения сайкл-тренировок нет &ndash; этим видом фитнеса можно заниматься как подросткам, так и людям пожилого возраста. Главное &ndash; строго соблюдать рекомендации врача и четко следовать инструкциям тренера.</p>\r\n\r\n<p>Противопоказания:<br />\r\n- сердечно-сосудистые заболевания;<br />\r\n- сильный варикоз.</p>\r\n\r\n<p>Первая тренировка уже в понедельник 20:00, успей записаться! Количество мест ограничено. Для резидентов клуба до конца ноября - бесплатно.<br />\r\n&nbsp;</p>','news_img/nWr5U5173gQ.jpg','news_img/nWr5U5173gQ_1cvOlSp.jpg','my-vse-etogo-ochen-zhdali','<p>Новое направление в групповых программах: &laquo;САЙКЛ-тренировка&raquo;.</p>'),(20,1,'2023-04-20 10:17:22.000000',20,'20 апреля санитарный день!','<p>Друзья,&nbsp;20 апреля санитарный день!&nbsp; Фитнес Клуб Эволюция не работает.&nbsp;</p>\r\n\r\n<p>8 (4912) 55-95-94.<br />\r\nДашково-Песочня, ул. Новоселов, 53Д</p>','news_img/-U49qz4mP6c.jpg','news_img/-U49qz4mP6c_YAuJyUq.jpg','20-aprelya-sanitarnyj-den','<p>Фитнес Клуб Эволюция не работает.</p>'),(21,1,'2023-06-28 00:12:28.000000',21,'29 июня Фитнес Клуб Эволюция отмечает свой четвертый день рождения!','<p>Друзья! Приглашаем отпраздновать это событие вместе с нами!&nbsp;<br />\r\n&nbsp;<br />\r\nВас ждет невероятный заряд драйва, а так же:<br />\r\n- командные соревнования во главе с нашими любимыми тренерами;<br />\r\n- мастер-классы;<br />\r\n- веселые конкурсы и интересные викторины;&nbsp;<br />\r\n- вечеринка;<br />\r\n- фуршет;<br />\r\n- розыгрыш призов и подарков.</p>\r\n\r\n<p>Море позитивных эмоций и приятных сюрпризов гарантировано!</p>\r\n\r\n<p>За атмосферу праздника ответственный наш друг и крутой ведущий - Павел Смирнов.</p>\r\n\r\n<p>Отправляйте в комментарии, если ждёте праздник также сильно, как и мы.<br />\r\n&nbsp;<br />\r\n29 июня сбор гостей в 18:00.&nbsp;<br />\r\nМесто проведения: Дашково-Песочня, ул. Новоселов, 53Д.</p>','news_img/B1ilvkqdcBw.jpg','news_img/B1ilvkqdcBw_dHM8IOp.jpg','29-iyunya-fitnes-klub-evolyuciya-otmechaet-svoj-ch','<p>Друзья! Приглашаем отпраздновать это событие вместе с нами!</p>');
