INSERT INTO `stock_stock` VALUES (6,0,'2021-09-11 12:09:24.000000',30,'+ 3 месяца в подарок','<p>Начинаем сезон с подарков!</p>','<p>Начинаем сезон с подарков!<br />\r\n3 месяца безлимитного фитнеса, абсолютно бесплатно, при покупке абонемента в Новую Эволюцию.<br />\r\nПорадуй себя или своих друзей!</p>','stock_img/2_rVo8vo2.jpg','stock_img/2_vGvlr5O.jpg','3-mesyaca-v-podarok'),(7,1,'2021-09-17 13:50:27.000000',31,'НИ В ЧЕМ СЕБЕ НЕ ОТКАЗЫВАЙ!','<p>Возвращаем 10% стоимости абонемента бонусами</p>','<p>Возвращаем 10% стоимости абонемента бонусами, которые можно потратить на любимое в Новой ЭВОЛЮЦИИ!</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани? Тогда пиши <a href=\"http://vk.me/evolution_rzn\" target=\"_blank\">vk.me/evolution_rzn</a> или звони <a href=\"tel:+74912559594\"><strong>+7&nbsp;(4912)&nbsp;55-95-94</strong></a>.</p>','stock_img/1_AVpnEnZ.jpg','stock_img/1_wbqpeWm.jpg','ni-v-chem-sebe-ne-otkazyvaj'),(8,0,'2021-09-17 13:53:16.000000',32,'2 абонемента по цене 1','<p>Возвращение самого горячего предложения этого лета!</p>','<p>По многочисленным просьбам!</p>\r\n\r\n<p>Возвращение самого горячего предложения этого лета -&nbsp;2 абонемента по цене 1</p>','stock_img/2_hEnGehP.jpg','stock_img/2_AF0DZvd.jpg','2-abonementa-po-cene-1'),(9,1,'2021-09-17 13:54:58.000000',33,'Студенческий год за 9900','<p>Не забудь добавить Фитнес в свое расписание!</p>','<p>Не забудь добавить Фитнес в свое расписание!</p>\r\n\r\n<p>Полный Безлимит + персональная тренировка + групповые занятия.</p>\r\n\r\n<p>Самые лучшие условия для студентов!</p>','stock_img/3.jpg','stock_img/3_KLWMBpl.jpg','studencheskij-god-za-9900'),(11,0,'2021-10-26 15:35:37.000000',34,'Экономь время и деньги вместе с Фитнес  клубом «Эволюция»!','<p>Это бомба!&nbsp;Карта, которую вы так ждали!!!</p>','<p>Экономь время и деньги вместе с Фитнес &nbsp;клубом &laquo;Эволюция&raquo;!</p>\r\n\r\n<p>Это бомба!<br />\r\nКарта, которую вы так ждали!!!<br />\r\n!100 ПОСЕЩЕНИЙ!</p>\r\n\r\n<p>Приходи, &nbsp;когда удобно, и посещай все зоны клуба!</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани? Тогда пиши, или звони!</p>\r\n\r\n<h2><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h2>','stock_img/2_bzDE35j.jpg','stock_img/2_2QC9KSz.jpg','ekonom-vremya-i-dengi-vmeste-s-fitnes-klubom-evoly'),(12,0,'2021-11-02 11:00:40.000000',35,'Продлеваем лучшее предложение этого сезона до 15 ноября!','<p>Крутые подарки, невероятные бонусы</p>','<p>Крутые подарки, невероятные бонусы</p>','stock_img/IMG_7123.JPG','stock_img/IMG_7123_bH6lMLt.JPG','prodlevaem-luchshee-predlozhenie-etogo-sezona-do-1'),(16,0,'2021-12-16 15:21:26.000000',36,'Самый мощный Новогодний подарок!','<p>Самый мощный Новогодний подарок от фитнес клуба Эволюция!</p>','<p>Пишите + что бы узнать подробности! Такого ещё не было!</p>','stock_img/IMG_7763.JPG','stock_img/IMG_7763_quv8nrT.JPG','samyj-moshnyj-novogodnij-podarok'),(17,0,'2022-01-13 18:42:23.000000',37,'Начни 2022 год правильно вместе с фитнес клубом Эволюция!','<p>А мы в свою очередь поможем вам крутой скидкой на абонемент.</p>','<p>А мы в свою очередь поможем вам крутой скидкой на абонемент.</p>\r\n\r\n<p>Пусть ваши тренировки в новом году будут такими же насыщенными как и ваше новогоднее застолье.</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани? Тогда пиши в Директ или звони.</p>','stock_img/IMG_8591.JPG','stock_img/IMG_8591_sZqvJ16.JPG','nachni-2022-god-pravilno-vmeste-s-fitnes-klubom-ev'),(20,0,'2022-03-04 12:56:20.000000',38,'Дорогие друзья!','<p>Дарим&nbsp;всем 2 месяца, при покупке полугодового абонемента!</p>','<p>Фитнес клуб Эволюция поздравляет вас с наступлением весны и дарит всем 2 месяца, при покупке полугодового абонемента!</p>\r\n\r\n<p>А милых дам, в честь 8 марта, порадуем ну ооочень приятными ценами!!!</p>\r\n\r\n<p>Подробности по телефону:</p>\r\n\r\n<h2><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h2>','stock_img/IMG_9805.PNG','stock_img/IMG_9805_PhiBapg.PNG','dorogie-druzya'),(21,0,'2022-05-12 14:26:57.000000',39,'Вместе – выгодно!','<p>&nbsp;Две клубные карты по горячей цене - 9000₽!</p>','<p>Две клубные карты по горячей цене 9000₽!&nbsp;</p>\r\n\r\n<p>Предложение действует до 10 мая!</p>\r\n\r\n<p>Подробности по телефону:</p>\r\n\r\n<h1><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h1>','stock_img/IMG_9127.JPG','stock_img/IMG_9127_BZWSvIg.JPG','vmeste-vygodno'),(22,0,'2022-05-13 16:37:24.000000',40,'Наши скидки такие же жаркие, как и угли в твоем мангале!','<p>Торопись, количество карт ограничено!</p>','<p>Торопись, количество карт ограничено!<br />\r\n<br />\r\nХочешь заниматься в одном из самых современных залов Рязани? Тогда звони:</p>\r\n\r\n<h1><a href=\"http://84912559594\" style=\"color: #ffffff;\"><strong>+7 (4912) 55-95-94</strong></a></h1>','stock_img/IMG_9431.PNG','stock_img/IMG_9431_uY1DhCv.PNG','nashi-skidki-takie-zhe-zharkie-kak-i-ugli-v-tvoem'),(23,0,'2022-05-27 12:42:31.000000',41,'Купи карту и занимайся с тренером БЕСПЛАТНО!','<p>Предложение действует только до 30&nbsp;мая.</p>','<p>Купи карту и занимайся с тренером БЕСПЛАТНО!</p>\r\n\r\n<p>Предложение действует только до 30&nbsp;мая.</p>\r\n\r\n<h1><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h1>\r\n\r\n<p>&nbsp;</p>','stock_img/IMG_0123.PNG','stock_img/IMG_0123_h36aCmK.PNG','kupi-kartu-i-zanimajsya-s-trenerom-besplatno'),(24,0,'2022-06-06 18:36:09.000000',42,'Жаркое предложение июня!','<p>Фитнес на весь ГОД за 6 900₽!</p>','<p>Фитнес на весь ГОД за 6 900₽!&nbsp;</p>\r\n\r\n<p>Подробности в отделе продаж!</p>\r\n\r\n<h1><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h1>','stock_img/IMG_0411.PNG','stock_img/IMG_0411_h0AfkSH.PNG','zharkoe-predlozhenie-iyunya'),(25,0,'2022-08-30 00:41:02.000000',43,'Почувствуй себя студентом!','<p>На 9 месяцев за 8 900 ₽!</p>\r\n\r\n<p>&nbsp;</p>','<p>Перед началом учебного года и нового фитнес-сезона<br />\r\nабонемент на <span style=\"font-size:20px\">9 месяцев</span> и <span style=\"font-size:20px\">90 дней </span>заморозки за <span style=\"font-size:20px\">8 900 ₽</span> для всех!<br />\r\n<br />\r\nХочешь заниматься в одном из самых современных залов Рязани? Тогда пиши&nbsp;или звони!</p>\r\n\r\n<h2><a href=\"http://84912559594\" style=\"color: #ffffff;\"><strong>+7 (4912) 55-95-94</strong></a></h2>','stock_img/whBSzHP_9aM.jpg','stock_img/whBSzHP_9aM_dNMVRKc.jpg','pochuvstvuj-sebya-studentom'),(26,1,'2022-09-08 15:34:35.000000',44,'Открыт набор на детские направления!','<p>Всех школьников и их родителей поздравляем с 1 сентября! Лёгкого учебного года и хороших оценок! А мы в свою очередь открываем набор по детским направлениям.</p>','<p>Всех школьников и их родителей поздравляем с 1 сентября! Лёгкого учебного года и хороших оценок! А мы в свою очередь открываем набор по детским направлениям.</p>\r\n\r\n<p>Фитнес клуб &laquo;Эволюция&raquo; - место в Рязани, где дети и подростки с увлечением смогут заниматься спортом и фитнесом под руководством профессионалов.&nbsp;Даже самые маленькие спортсмены будут чувствовать себя комфортно и безопасно.</p>\r\n\r\n<p>Направления занятий:</p>\r\n\r\n<ul>\r\n	<li>ОФП;</li>\r\n	<li>рукопашный бой;</li>\r\n	<li>карате;</li>\r\n	<li>бокс.</li>\r\n</ul>\r\n\r\n<p>По вопросам записи на групповые занятия и приобретения абонемента пишите<strong> <a href=\"http://vk.me/evolution_rzn\" target=\"_blank\">vk.me/evolution_rzn</a> </strong>или звоните: <a href=\"tel:+74912559594\"><strong>+7&nbsp;(4912)&nbsp;55-95-94</strong></a></p>','stock_img/08-09-22.jpg','stock_img/08-09-22_F8qeFeY.jpg','otkryt-nabor-na-detskie-napravleniya'),(27,0,'2022-09-08 15:46:10.000000',45,'Классные цены на фитнес!','<p>Классные цены на фитнес!</p>\r\n\r\n<p>Все включено: групповые занятия, тренажёрный зал.</p>','<p>Классные цены на фитнес!</p>\r\n\r\n<p>Все включено: групповые занятия, тренажёрный зал.</p>\r\n\r\n<p>50 &laquo;уроков&raquo; &ndash; 8 900 на 12 месяцев, 100 &laquo;уроков&raquo; &ndash; 10 900 на 24 месяца.</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани? Тогда пиши <strong> <a href=\"https://vk.me/evolution_rzn\" style=\"color:#ffffff;\" target=\"_blank\">vk.me/evolution_rzn</a> </strong>или звони:&nbsp;<a href=\"tel:+74912559594\" style=\"color: #ffffff;\"><strong>+7 (4912) 55-95-94</strong></a>.</p>','stock_img/08-09-22-2.jpg','stock_img/08-09-22-2_FyWbog8.jpg','klassnye-ceny-na-fitnes'),(28,0,'2022-09-27 01:44:50.000000',46,'Только 5 дней - фитнес за 8 900₽!','<p>Предложение действует до 30 сентября.</p>','<p>Хочешь заниматься в одном из самых современных залов Рязани?<br />\r\n<br />\r\nТогда пиши <a href=\"http://vk.me/evolution_rzn\">vk.me/evolution_rzn</a> или звони <span style=\"font-size:20px\">8 (4912) 55-95-94</span>.</p>','stock_img/JTtTXFXJL6w.jpg','stock_img/JTtTXFXJL6w_4L77fDH.jpg','tolko-5-dnej-fitnes-za-8-900'),(30,1,'2022-10-15 10:54:58.000000',47,'Счастливые часы на фитнес!','<p>При покупке абонемента с 12:00 до 16:00 действует скидка -20% от прайса.</p>','<p>Счастливые часы на фитнес!</p>\r\n\r\n<p>При покупке абонемента с 12:00 до 16:00 действует скидка -20% от прайса.<br />\r\n<br />\r\nХочешь заниматься в одном из самых современных залов Рязани? Тогда пиши&nbsp;или звони!</p>\r\n\r\n<h2><a href=\"tel:+74912559594\"><strong>+7 (4912) 55-95-94</strong></a></h2>','stock_img/6G5zt24KM90.jpg','stock_img/6G5zt24KM90_qQRxvRL.jpg','schastlivye-chasy-na-fitnes'),(31,0,'2022-10-27 16:55:55.000000',48,'Страшно выгодно!','<p>13 месяцев в году!</p>','<p>Предложение действует до 31 октября.</p>\r\n\r\n<p>Подробности в отделе продаж.<br />\r\n<br />\r\nХочешь заниматься в одном из самых современных залов Рязани? Тогда пиши&nbsp;или звони!</p>\r\n\r\n<h2><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h2>','stock_img/PufLrmULRms.jpg','stock_img/PufLrmULRms_2De8boN.jpg','strashno-vygodno'),(33,0,'2022-11-15 21:03:27.000000',49,'12 месяцев дневного фитнеса + 90 дней заморозки за 8 000₽!','<p>...</p>','<p>Время посещения по дневному абонементу:<span style=\"font-size:20px\"> с 6:00 до 17:00</span>.</p>\r\n\r\n<p>Подробности в отделе продаж или по телефону&nbsp;</p>\r\n\r\n<p><span style=\"font-size:20px\">8 (4912) 55-95-94</span></p>','stock_img/N8c8czrjinc.jpg','stock_img/N8c8czrjinc_1Di5srv.jpg','12-mesyacev-dnevnogo-fitnesa-90-dnej-zamorozki-za'),(35,0,'2022-12-19 20:37:16.000000',50,'Лучший подарок к Новому году!','<p>12 месяцев фитнеса за 10 000₽!</p>','<p>Хочешь заниматься в одном из самых современных залов Рязани?</p>\r\n\r\n<p>Тогда пиши vk.me/evolution_rzn</p>\r\n\r\n<p>или звони <span style=\"font-size:20px\">8 (4912) 55-95-94</span>.</p>','stock_img/Kq0zttLoEAg.jpg','stock_img/Kq0zttLoEAg_XVWBk40.jpg','luchshij-podarok-k-novomu-godu'),(36,0,'2023-01-16 22:17:00.000000',51,'То, что сегодня кажется невозможным, завтра станет вашей разминкой.','<p>Тренируйся в любое время за 9 900 ₽.</p>','<p>Торопись, акция действует до 25 января.&nbsp;</p>\r\n\r\n<p>Подробности в отделе продаж!</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани?</p>\r\n\r\n<p>Тогда пиши vk.me/evolution_rzn</p>\r\n\r\n<p>или звони&nbsp;<a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></p>','stock_img/iaHzVpDvUdQ.jpg','stock_img/iaHzVpDvUdQ_6KY4aEx.jpg','chto-segodnya-kazhetsya-nevozmozhnym-zavtra-stanet'),(37,0,'2023-02-03 13:57:35.000000',52,'Для влюблённых в фитнес!','<p>Абонемент на двоих за&nbsp;20 000₽!</p>','<p>Тренируйтесь вместе с максимальной выгодой.&nbsp;</p>\r\n\r\n<p>Торопись, акция действует до 15 февраля.<br />\r\n<br />\r\nХочешь заниматься в одном из самых современных залов Рязани?</p>\r\n\r\n<p>Тогда пиши vk.me/evolution_rzn</p>\r\n\r\n<p>или звони&nbsp;<a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></p>','stock_img/fg0igZis_QU.jpg','stock_img/fg0igZis_QU_JUoCx2j.jpg','dlya-vlyublyonnyh-v-fitnes'),(38,0,'2023-02-17 12:15:17.000000',53,'Для сильных телом и духом','<p>В честь Дня защитника Отечества супер-акция!</p>','<p>В честь Дня защитника Отечества супер-акция: <strong>6 месяцев&nbsp;фитнеса&nbsp;за 9&nbsp;000₽ + 2&nbsp;месяца в подарок + 3&nbsp;месяца заморозки</strong>!</p>\r\n\r\n<p>Подробности в отделе продаж или по телефону:<br />\r\n<strong><a href=\"tel: +74912559594\">8 (4912) 55-95-94</a></strong>.</p>','stock_img/1-min.jpg','stock_img/1-min_xSpmufx.jpg','dlya-silnyh-telom-i-duhom'),(39,0,'2023-04-27 13:11:55.000000',54,'Фитнес год за 9 000₽!','<p>Торопись, акция действует до 30 апреля.</p>','<p>Хочешь заниматься в одном из самых современных залов Рязани?</p>\r\n\r\n<p>Тогда пиши vk.me/evolution_rzn</p>\r\n\r\n<p>или звони&nbsp;<a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></p>','stock_img/zISf9g7dMWw.jpg','stock_img/zISf9g7dMWw_9wTC1SZ.jpg','fitnes-god-za-9-000'),(40,0,'2023-05-10 12:42:34.000000',55,'Занимайся с тренером от 6000₽!','<p>Услуги тренера включены в стоимость абонемента.<br />\r\n&nbsp;</p>','<p>Услуги тренера включены в стоимость абонемента.</p>\r\n\r\n<p>*Персонального тренера можно выбрать из предложенного списка.&nbsp;</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани?</p>\r\n\r\n<p>Тогда пиши vk.me/evolution_rzn</p>\r\n\r\n<p>или звони&nbsp;<a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></p>','stock_img/LMXCxmlDfuM.jpg','stock_img/LMXCxmlDfuM_ml5yqcW.jpg','fitnes-s-trenerom-ot-6-000'),(41,0,'2023-07-28 12:50:34.000000',56,'Очень выгодное предложение!','<p>Только 3 дня!</p>','<p>Год безлимитного фитнеса за <span style=\"font-size:18px\"><strong>9 900</strong></span><span style=\"font-size:14px\"><strong>₽</strong></span>!&nbsp;<br />\r\n<br />\r\nХочешь заниматься в одном из самых современных залов Рязани? Тогда пиши&nbsp;или звони!</p>\r\n\r\n<h2><a href=\"http://84912559594\"><strong>+7 (4912) 55-95-94</strong></a></h2>','stock_img/JH4dwhMpEbQ.jpg','stock_img/JH4dwhMpEbQ_NuJGFPj.jpg','ochen-vygodnoe-predlozhenie'),(42,1,'2023-09-14 14:11:00.000000',29,'12 месяцев дневного фитнеса - 8 000₽!','<p>Время посещения по дневному абонементу:<strong> </strong>с 6:00 до 17:00.</p>','<p>Время посещения по дневному абонементу:<strong> с 6:00 до 17:00</strong>. Подробности в отделе продаж.</p>\r\n\r\n<p>Хочешь заниматься в одном из самых современных залов Рязани? Тогда пиши <a href=\"http://vk.me/evolution_rzn\" target=\"_blank\">vk.me/evolution_rzn</a> или звони <a href=\"tel:+74912559594\"><strong>+7&nbsp;(4912)&nbsp;55-95-94</strong></a>.</p>','stock_img/image-14-09-23-13-30.jpeg','stock_img/image-14-09-23-13-30_sZpAvqV.jpeg','12-mesyacev-dnevnogo-fitnesa-8-000');
