INSERT INTO `team_team` VALUES (2,1,'2021-08-09 16:19:07.000000',2,'ВАСИЛИЙ АФОНЬКИН','Персональный тренер','<p>Специалист в области фитнеса, кинезиологии, оздоровительной физкультуры и работе с различными трудностями опорно-двигательного аппарата.</p>\r\n\r\n<p>Специализируюсь на развитии силовых показателей, увеличении активной мышечной массы, укреплении мышц для стабилизации опорно-двигательного аппарата, а также функциональном тренинге. Готов оказать диетологическое сопровождение в тренировках.<br />\r\nДоставляет удовольствие помогать людям достигать поставленные цели, мотивировать и приводить к желаемому результату.</p>','team_img/afonkin-1_26ov4pL.jpg','team_img/afonkin-2_R5Ja9ok.jpg','vasilij-afonkin'),(3,1,'2021-08-09 16:19:36.000000',3,'АРТЁМ БИЗЮКОВ','Фитнес-эксперт, старший тренер фитнес-клуба «Эволюция»','<p>- Неоднократный участник и призер чемпионатов, всероссийских и областных турниров по пауэрлифтингу и отдельным его движениям.<br />\r\n<br />\r\n- 2-х кратный Мастер спорта по жиму лежа в легкой и жесткой экипировке.<br />\r\n<br />\r\n- Кандидат в мастера спорта по жиму лежа без экипировки.<br />\r\n<br />\r\n-&nbsp;Сертифицированный специалист по спортивной нутрициологии, эндокринологии в фитнесе и бодибилдинге, спортивном питании и эргогенным средствам, работе с людьми с нарушением опорно-двигательного аппарата, прикладной кинезиологии, а также гормонозаместительной терапии.&nbsp;<br />\r\n<br />\r\nГотов помогать тренироваться людям с различным уровнем здоровья.&nbsp;Главное помнить, что быстро &ndash; это медленно, но постоянно!</p>','team_img/bizukov-1_c9tmL6T.jpg','team_img/bizukov-2_E5s3z6t.jpg','artyom-bizyukov'),(5,1,'2021-08-13 15:40:23.000000',5,'КИРИЛЛ ГРИДНЕВСКИЙ','Персональный тренер','<p>Специализация на силовых направлениях, оздоровительной физкультуре и функциональном тренинге.<br />\r\nГотов подготовить Вас к соревнованиям по силовым видам спорта.<br />\r\nДа что тут долго говорить, приходите на тренировку,&nbsp;и я помогу Вам стать сильнее и лучше!</p>','team_img/gridnevskiy-1.jpg','team_img/gridnevskiy-2.jpg','kirill-gridnevskij'),(6,1,'2021-08-13 15:40:54.000000',6,'ГРИГОРИЙ ДОРОГОВ','Персональный тренер','<p>Специализируюсь на коррекции фигуры, укреплении мышечного корсета и опорно-двигательного аппарата.</p>\r\n\r\n<p>Подготовлю к соревнованиям по пауэрлифтингу.<br />\r\nРаботаю с различными возрастными категориями:&nbsp;от детишек до пожилых людей.</p>\r\n\r\n<p>Работаю с различными типами осанки и прочими заболеваниями.</p>\r\n\r\n<p>КМС по Пауэрлифтингу. Чемпион и призер чемпионатов Рязани, области и ЦФО по самбо. Призер открытых чемпионатов Рязани по бодибилдингу (категория юноши, юниоры).<br />\r\nГотов помочь Вам в оздоровлении Вашего тела и духа!&nbsp;</p>','team_img/dorogov-1.jpg','team_img/dorogov-2.jpg','grigorij-dorogov'),(7,1,'2021-08-13 15:41:22.000000',7,'ЛЮДМИЛА БИЗЮКОВА','Персональный тренер','<p>Специализируюсь на женском фитнесе, помогу в улучшении ваших форм, а также в восстановлении после родов.<br />\r\nС удовольствием работаю с будущими мамами.<br />\r\nВ спорте с самого детства, являюсь кандидат в мастера спорта по волейболу<br />\r\nВходила в состав сборной Рязани по волейболу, призёр всероссийских соревнований высшей лиги Б<br />\r\nГотова помочь в обретении гармонии между телом и духом, ведь для нас девочек, это очень важно!</p>','team_img/karpova-1.jpg','team_img/karpova-2.jpg','lyudmila-karpova'),(8,1,'2021-08-13 15:41:52.000000',8,'АЛЕКСАНДР МАХОНИН','Персональный фитнес-тренер','<p>- Мастер спорта России по пауэрлифтингу, мастер спорта международного класса по жиму лежа.&nbsp;<br />\r\n<br />\r\n-&nbsp;Специалист в области спортивного оздоровления, развития силовых показателей, а так же кинезиологии, кинезио-тейпирования и коррекции опорно-двигательного аппарата.<br />\r\n<br />\r\nПомогу обрести здоровье, силу и красоту.&nbsp;<br />\r\n<br />\r\nГотов подготовить Вас&nbsp;как к соревнованиям, так и к пляжному сезону.</p>','team_img/mahonin-1.jpg','team_img/mahonin-2.jpg','aleksandr-mahonin'),(9,1,'2021-08-13 15:42:22.000000',9,'ЮЛИЯ ПАНКРАТОВА','Сертифицированный инструктор групповых программ и персональный тренер','<p>Образование высшее.<br />\r\nЗанончила Санкт-Петербургскую академию культуры. Специальность по диплому: &laquo;Преподаватель хореографических дисциплин&raquo;. Балетмейстер по специальности &laquo;Хореографическое искусство&raquo;.</p>\r\n\r\n<p>Дополнительное образование: сертификаты FISAF, КСФ по направлениям: &laquo;Йога&raquo;, &laquo;Танцевальная аэробика&raquo;, &laquo;Классическая аэробика&raquo;, &laquo;Степ-аэробика&raquo;, &laquo;Силовая тренировка&raquo;, &laquo;Функциональная тренировка&raquo;, &laquo;Стретчинг&raquo;, &laquo;Пилатес&raquo;.<br />\r\nДиплом о профессиональной переподготовке Национального Университета Фитнеса.</p>\r\n\r\n<p>Участница международных конвенций и семинаров World class,&nbsp;семинара А. Шапочки &laquo;Новый взгляд на стретчинг&raquo;,&nbsp;семинаров по йогатерапии при проблемах опорно-двигательного аппарата.</p>\r\n\r\n<p>В спорте с 4 лет, в фитнесе с 2000 года.</p>\r\n\r\n<p>Достижения: 1 взрослый разряд по фигурному катанию, премия на танцевальном конкурсе &laquo;Музы Санкт-Петербурга&raquo;.</p>\r\n\r\n<p>Увлечения: велосипед, туризм.<br />\r\nОсновные направления: силовая аэробика, круговой тренинг, интервальный тренинг, табата, Hilt, abl, функциональный тренинг, суставная гимнастика, йога, йога-терапия.</p>\r\n\r\n<p>Мой девиз &ndash;&nbsp;&laquo;Движение &ndash;&nbsp;жизнь&raquo;.</p>','team_img/pankratova-1.jpg','team_img/pankratova-2.jpg','yuliya-pankratova'),(10,1,'2021-08-13 15:42:48.000000',10,'ГАЛИНА РОЙТБУРД','Тренер групповых программ','<p>Закончила РФ МГУКиИ.</p>\r\n\r\n<p>Сертифицированный инструктор в образовательном центре &laquo;Академия фитнеса&raquo; г. Москва и &laquo;Fitness Express&raquo; г. Москва.</p>\r\n\r\n<p>Сертифицированный инструктор направлений: латина, джаз модерн, вакинг, детский фитнес, суставная гимнастика, стрип денс, танец живота, танцевальная терапия ,стретчинг, танцевальная аэробика, функциональный тренинг.</p>\r\n\r\n<p>Моя авторская программа &laquo;Геометрия тела&raquo;.</p>\r\n\r\n<p>Участница различных конференций, мастер классов, танцевальных фестивалей и конкурсов.</p>\r\n\r\n<p>Стаж тренерской работы более 20 лет. Из них 10 лет работы в школе учителем ритмики и истории хореографии, а также руководителем ансамбля танца &laquo;Ритм&raquo;.</p>\r\n\r\n<p>&laquo;Для меня танец &ndash; это мой воздух, вся моя жизнь в танце. Если движение &ndash; это жизнь, то танец &ndash; прекрасная жизнь. Это потрясающие эмоции, отличное настроение, заряд энергии, путь к счастью, красоте, здоровью и гармонии&raquo;.&nbsp;</p>','team_img/roitburd-1.jpg','team_img/roitburd-2.jpg','galina-rojtburd'),(11,1,'2021-08-13 15:43:26.000000',11,'НИКОЛАЙ САРАЕВ','Самый позитивный персональный тренер','<p>Специалист в силовом и функциональном тренинге, готов разбавить тренировки занятиями по боксу.<br />\r\nРаботаю с различными возрастными категориями.<br />\r\nГотов менять людей не только внешне, но и внутренне.&nbsp;Помогу человеку поверить в себя и заряжу позитивным настроением, жизненной энергией!</p>','team_img/saraev-1.jpg','team_img/saraev-2.jpg','nikolaj-saraev'),(13,0,'2021-08-13 15:44:24.000000',13,'РУСТАМ СТРЕКАЛОВ','Персональный фитнес-тренер','<p>Персональный фитнес-тренер, который готов разбавить привычные всем тренировки в зале работой на лапах и мешке, ведь помимо зала, активно занимаюсь боксом.<br />\r\n&nbsp;<br />\r\nСпециализируюсь на силовом и функциональном тренинге.&nbsp;<br />\r\nГотов познакомить вас с кроссфит направлением, подготовить к соревнованиям в силовых дисциплинах.<br />\r\nСертифицированный специалист в области фитнеса и нутрициологии.</p>','team_img/strekalov-1.jpg','team_img/strekalov-2.jpg','rustam-strekalov'),(14,1,'2021-08-13 15:44:55.000000',14,'АНАСТАСИЯ ХОМЕНКО','Координатор групповых направлений, персональный тренер.','<p>- Дипломированный физрук-ботаник.<br />\r\n<br />\r\n-&nbsp;Тренер-преподаватель, со знаниями анатомии и биомеханики.<br />\r\n<br />\r\nДевиз: &laquo;Здоровое тело через осознанное движение&raquo;.<br />\r\n<br />\r\nТренер-универсал.&nbsp;Три международных сертификата в области биомеханики движения и множество сертификатов по таким направлениям, как пилатес, функциональный тренинг, фасциальный стретчинг.<br />\r\n<br />\r\nПоможет улучшить технику движения, расскажет как и что работает. Научит как развить функциональность тела, его силу, гибкость, выносливость, улучшить координацию.<br />\r\n<br />\r\nАвтор программы &laquo;Здоровая спина&raquo;, с использованием трёхплоскостного движения.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>&nbsp;</p>','team_img/homenko-1.jpg','team_img/homenko-2.jpg','anastasiya-homenko');
